class CategoryType(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    description = graphene.String()
    products = graphene.List(lambda: ProductType)

    def resolve_products(self, info):
        return [p for p in PRODUCTS if p['category_id'] == self.id]


class ReviewType(graphene.ObjectType):
    id = graphene.ID()
    product_id = graphene.ID()
    user_name = graphene.String()
    rating = graphene.Int()
    comment = graphene.String()
    created_at = graphene.DateTime()


class ProductType(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    description = graphene.String()
    price = graphene.Float()
    category_id = graphene.ID()
    stock = graphene.Int()
    created_at = graphene.DateTime()
    category = graphene.Field(CategoryType)
    reviews = graphene.List(ReviewType)
    average_rating = graphene.Float()

    def resolve_category(self, info):
        category = next((c for c in CATEGORIES if c['id'] == self.category_id), None)
        if category:
            return CategoryType(**category)
        return None

    def resolve_reviews(self, info):
        product_reviews = [r for r in REVIEWS if r['product_id'] == self.id]
        return [ReviewType(**r) for r in product_reviews]

    def resolve_average_rating(self, info):
        product_reviews = [r for r in REVIEWS if r['product_id'] == self.id]
        if not product_reviews:
            return None
        total_rating = sum(r['rating'] for r in product_reviews)
        return round(total_rating / len(product_reviews), 2)


class Query(graphene.ObjectType):
    products = graphene.List(
        ProductType,
        category_id=graphene.ID(),
        min_price=graphene.Float(),
        max_price=graphene.Float(),
        search=graphene.String()
    )
    product = graphene.Field(ProductType, id=graphene.ID(required=True))
    
    categories = graphene.List(CategoryType)
    category = graphene.Field(CategoryType, id=graphene.ID(required=True))
    
    reviews = graphene.List(ReviewType, product_id=graphene.ID())
    review = graphene.Field(ReviewType, id=graphene.ID(required=True))

    def resolve_products(self, info, category_id=None, min_price=None, max_price=None, search=None):
        filtered_products = PRODUCTS

        if category_id:
            filtered_products = [p for p in filtered_products if p['category_id'] == category_id]

        if min_price is not None:
            filtered_products = [p for p in filtered_products if p['price'] >= min_price]

        if max_price is not None:
            filtered_products = [p for p in filtered_products if p['price'] <= max_price]

        if search:
            search_lower = search.lower()
            filtered_products = [
                p for p in filtered_products 
                if search_lower in p['name'].lower() or search_lower in p['description'].lower()
            ]

        return [ProductType(**p) for p in filtered_products]

    def resolve_product(self, info, id):
        product = next((p for p in PRODUCTS if p['id'] == id), None)
        if product:
            return ProductType(**product)
        return None

    def resolve_categories(self, info):
        return [CategoryType(**c) for c in CATEGORIES]

    def resolve_category(self, info, id):
        category = next((c for c in CATEGORIES if c['id'] == id), None)
        if category:
            return CategoryType(**category)
        return None

    def resolve_reviews(self, info, product_id=None):
        filtered_reviews = REVIEWS
        if product_id:
            filtered_reviews = [r for r in filtered_reviews if r['product_id'] == product_id]
        return [ReviewType(**r) for r in filtered_reviews]

    def resolve_review(self, info, id):
        review = next((r for r in REVIEWS if r['id'] == id), None)
        if review:
            return ReviewType(**review)
        return None


class CreateReview(graphene.Mutation):
    class Arguments:
        product_id = graphene.ID(required=True)
        user_name = graphene.String(required=True)
        rating = graphene.Int(required=True)
        comment = graphene.String(required=True)

    review = graphene.Field(ReviewType)

    def mutate(self, info, product_id, user_name, rating, comment):
        product = next((p for p in PRODUCTS if p['id'] == product_id), None)
        if not product:
            raise Exception('Product not found')

        if rating < 1 or rating > 5:
            raise Exception('Rating must be between 1 and 5')

        new_review = {
            'id': str(len(REVIEWS) + 1),
            'product_id': product_id,
            'user_name': user_name,
            'rating': rating,
            'comment': comment,
            'created_at': datetime.now()
        }
        REVIEWS.append(new_review)
        return CreateReview(review=ReviewType(**new_review))


class CreateProduct(graphene.Mutation):
    class Arguments:
        name = graphene.String(required=True)
        description = graphene.String(required=True)
        price = graphene.Float(required=True)
        category_id = graphene.ID(required=True)
        stock = graphene.Int(required=True)

    product = graphene.Field(ProductType)

    def mutate(self, info, name, description, price, category_id, stock):
        category = next((c for c in CATEGORIES if c['id'] == category_id), None)
        if not category:
            raise Exception('Category not found')

        if price <= 0:
            raise Exception('Price must be greater than 0')

        if stock < 0:
            raise Exception('Stock cannot be negative')

        new_product = {
            'id': str(len(PRODUCTS) + 1),
            'name': name,
            'description': description,
            'price': price,
            'category_id': category_id,
            'stock': stock,
            'created_at': datetime.now()
        }
        PRODUCTS.append(new_product)
        return CreateProduct(product=ProductType(**new_product))


class UpdateProduct(graphene.Mutation):
    class Arguments:
        id = graphene.ID(required=True)
        name = graphene.String()
        description = graphene.String()
        price = graphene.Float()
        category_id = graphene.ID()
        stock = graphene.Int()

    product = graphene.Field(ProductType)

    def mutate(self, info, id, name=None, description=None, price=None, category_id=None, stock=None):
        product = next((p for p in PRODUCTS if p['id'] == id), None)
        if not product:
            raise Exception('Product not found')

        if name is not None:
            product['name'] = name
        if description is not None:
            product['description'] = description
        if price is not None:
            if price <= 0:
                raise Exception('Price must be greater than 0')
            product['price'] = price
        if category_id is not None:
            category = next((c for c in CATEGORIES if c['id'] == category_id), None)
            if not category:
                raise Exception('Category not found')
            product['category_id'] = category_id
        if stock is not None:
            if stock < 0:
                raise Exception('Stock cannot be negative')
            product['stock'] = stock

        return UpdateProduct(product=ProductType(**product))


class Mutation(graphene.ObjectType):
    create_review = CreateReview.Field()
    create_product = CreateProduct.Field()
    update_product = UpdateProduct.Field()


schema = graphene.Schema(query=Query, mutation=Mutation)

